const item = $input.first().json;
const emailBody = item.snippet || '';
const subject = item.Subject || '';
const from = item.From || '';

let cleanBody = emailBody.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
cleanBody = cleanBody
  .replace(/ignore (all |any )?(previous |prior |above )?instructions/gi, '[REMOVED]')
  .replace(/you are now/gi, '[REMOVED]')
  .replace(/new instructions:/gi, '[REMOVED]')
  .replace(/system prompt/gi, '[REMOVED]')
  .replace(/\[INST\]/gi, '[REMOVED]')
  .replace(/<\|im_start\|>/gi, '[REMOVED]')
  .replace(/```(system|assistant)/gi, '[REMOVED]');
cleanBody = cleanBody.substring(0, 3000);

return [{
  json: {
    sanitizedBody: cleanBody,
    subject: subject.substring(0, 200),
    from: from.substring(0, 200)
  }
}];

const agentOutput = $input.first().json.output;

// Parse JSON from agent output
let jsonStr = agentOutput;
if (jsonStr.includes('```')) {
  jsonStr = jsonStr.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
}

let data;
try {
  data = JSON.parse(jsonStr);
} catch(e) {
  const match = jsonStr.match(/\{[\s\S]*\}/);
  if (match) data = JSON.parse(match[0]);
  else throw new Error('Could not parse agent output as JSON: ' + e.message);
}

const companies = data.companies || [];
const sectorOverview = data.sector_overview || '';
const comparativeAnalysis = data.comparative_analysis || '';
const keyThemes = data.key_themes || [];

// === BUILD EXCEL DATA ===
// Main company sheet
const companyRows = companies.map(c => ({
  'Company': c.name, 'Ticker': c.ticker, 'Exchange': c.exchange,
  'Sector': c.sector, 'Industry': c.industry, 'HQ': c.headquarters,
  'CEO': c.ceo, 'Founded': c.founded, 'Employees': c.employees,
  'Market Cap': c.market_cap, 'Enterprise Value': c.enterprise_value,
  'Revenue (LTM)': c.revenue_ltm, 'Rev Growth YoY': c.revenue_growth_yoy,
  'EBITDA': c.ebitda, 'EBITDA Margin': c.ebitda_margin,
  'Net Income': c.net_income, 'EPS': c.eps,
  'P/E': c.pe_ratio, 'EV/EBITDA': c.ev_ebitda, 'EV/Revenue': c.ev_revenue,
  'P/B': c.pb_ratio, 'Debt/EBITDA': c.debt_to_ebitda,
  'Interest Coverage': c.interest_coverage,
  'FCF': c.fcf, 'FCF Yield': c.fcf_yield,
  'Div Yield': c.dividend_yield, 'ROE': c.roe, 'ROIC': c.roic,
  '52W High': c['52w_high'], '52W Low': c['52w_low'],
  'Moat': c.competitive_moat,
  'Bull Case': c.investment_thesis?.bull_case,
  'Base Case': c.investment_thesis?.base_case,
  'Bear Case': c.investment_thesis?.bear_case
}));

// Comps sheet
const compsRows = [];
for (const c of companies) {
  for (const comp of (c.comps || [])) {
    compsRows.push({
      'Target': c.name, 'Peer': comp.name, 'Peer Ticker': comp.ticker,
      'Mkt Cap': comp.market_cap, 'EV/Revenue': comp.ev_revenue,
      'EV/EBITDA': comp.ev_ebitda, 'P/E': comp.pe_ratio,
      'Rev Growth': comp.revenue_growth, 'EBITDA Margin': comp.ebitda_margin
    });
  }
}

// === BUILD HTML REPORT ===
let html = `<html><head><style>
  body { font-family: 'Georgia', 'Times New Roman', serif; max-width: 960px; margin: 0 auto; padding: 30px; color: #1a1a1a; line-height: 1.6; }
  h1 { color: #003366; border-bottom: 3px solid #003366; padding-bottom: 12px; font-size: 28px; }
  h2 { color: #003366; margin-top: 35px; border-bottom: 2px solid #ccc; padding-bottom: 8px; font-size: 22px; }
  h3 { color: #1a5276; font-size: 18px; }
  h4 { color: #2c3e50; font-size: 15px; margin-bottom: 5px; }
  .company-section { margin: 25px 0; page-break-inside: avoid; }
  .metrics-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 8px; margin: 15px 0; }
  .metric-box { background: #f7f9fc; padding: 10px; border-radius: 4px; border: 1px solid #dce4ec; text-align: center; }
  .metric-label { font-size: 10px; color: #666; text-transform: uppercase; letter-spacing: 0.5px; }
  .metric-value { font-size: 18px; font-weight: bold; color: #003366; margin-top: 2px; }
  table { width: 100%; border-collapse: collapse; margin: 15px 0; font-size: 13px; }
  th { background: #003366; color: white; padding: 10px 8px; text-align: left; font-weight: 600; }
  td { padding: 8px; border-bottom: 1px solid #e0e0e0; }
  tr:nth-child(even) { background: #f8f9fa; }
  .swot { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin: 15px 0; }
  .swot-box { padding: 14px; border-radius: 6px; font-size: 13px; }
  .s-box { background: #e8f5e9; border-left: 4px solid #2e7d32; }
  .w-box { background: #fce4ec; border-left: 4px solid #c62828; }
  .o-box { background: #e3f2fd; border-left: 4px solid #1565c0; }
  .t-box { background: #fff3e0; border-left: 4px solid #e65100; }
  .dcf-box { background: #f3e5f5; padding: 15px; border-radius: 6px; border-left: 4px solid #7b1fa2; margin: 15px 0; }
  .ma-box { background: #fff8e1; padding: 15px; border-radius: 6px; border-left: 4px solid #f9a825; margin: 15px 0; }
  .thesis-box { background: #e8eaf6; padding: 15px; border-radius: 6px; margin: 10px 0; }
  .bull { border-left: 4px solid #2e7d32; }
  .base { border-left: 4px solid #1565c0; }
  .bear { border-left: 4px solid #c62828; }
  .risk-section { background: #fff5f5; padding: 15px; border-radius: 6px; margin: 15px 0; }
  .moat { display: inline-block; padding: 3px 10px; border-radius: 10px; font-size: 12px; font-weight: bold; }
  .moat-wide { background: #2e7d32; color: white; }
  .moat-narrow { background: #f9a825; color: #333; }
  .moat-none { background: #e0e0e0; color: #666; }
  .catalyst { background: #e0f2f1; padding: 6px 12px; margin: 4px 0; border-radius: 4px; border-left: 3px solid #00897b; font-size: 13px; }
  .overview-box { background: #e8eaf6; padding: 18px; border-radius: 8px; margin: 20px 0; }
  .themes { display: flex; gap: 10px; flex-wrap: wrap; margin: 10px 0; }
  .theme-tag { background: #003366; color: white; padding: 6px 14px; border-radius: 16px; font-size: 13px; }
  .disclaimer { background: #f5f5f5; padding: 15px; border-radius: 6px; font-size: 11px; color: #888; margin-top: 40px; border: 1px solid #e0e0e0; }
  .confidential { color: #c62828; font-weight: bold; text-align: center; font-size: 11px; text-transform: uppercase; letter-spacing: 2px; margin-bottom: 20px; }
  ul { padding-left: 18px; margin: 5px 0; }
  li { margin: 3px 0; font-size: 13px; }
</style></head><body>`;

html += `<div class="confidential">Confidential — For Internal Use Only</div>`;
html += `<h1>Investment Banking Research Report</h1>`;
html += `<p><em>Generated ${new Date().toISOString().split('T')[0]} | ${companies.length} companies analyzed</em></p>`;

if (keyThemes.length) {
  html += `<div class="themes">${keyThemes.map(t => `<span class="theme-tag">${t}</span>`).join('')}</div>`;
}

if (sectorOverview) {
  html += `<div class="overview-box"><h3>Sector Overview</h3><p>${sectorOverview}</p></div>`;
}

for (const c of companies) {
  const moatClass = (c.competitive_moat || '').includes('wide') ? 'wide' : (c.competitive_moat || '').includes('narrow') ? 'narrow' : 'none';

  html += `<div class="company-section">`;
  html += `<h2>${c.name} (${c.ticker || 'N/A'}) — ${c.exchange || ''} <span class="moat moat-${moatClass}">${c.competitive_moat || 'N/A'} moat</span></h2>`;
  html += `<p><strong>${c.sector || ''}</strong> | ${c.industry || ''} | ${c.headquarters || ''}</p>`;
  html += `<p>${c.business_description || ''}</p>`;

  // Key Metrics Grid
  const metrics = [
    ['Market Cap', c.market_cap], ['EV', c.enterprise_value],
    ['Revenue', c.revenue_ltm], ['Rev Growth', c.revenue_growth_yoy],
    ['EBITDA', c.ebitda], ['EBITDA Margin', c.ebitda_margin],
    ['Net Income', c.net_income], ['EPS', c.eps],
    ['P/E', c.pe_ratio], ['EV/EBITDA', c.ev_ebitda],
    ['EV/Revenue', c.ev_revenue], ['P/B', c.pb_ratio],
    ['Debt/EBITDA', c.debt_to_ebitda], ['FCF', c.fcf],
    ['FCF Yield', c.fcf_yield], ['ROE', c.roe]
  ];
  html += `<h3>Financial Summary</h3><div class="metrics-grid">`;
  for (const [label, val] of metrics) {
    if (val) html += `<div class="metric-box"><div class="metric-label">${label}</div><div class="metric-value">${val}</div></div>`;
  }
  html += `</div>`;

  // Comps Table
  if (c.comps && c.comps.length) {
    html += `<h3>Comparable Companies</h3><table><tr><th>Company</th><th>Ticker</th><th>Mkt Cap</th><th>EV/Rev</th><th>EV/EBITDA</th><th>P/E</th><th>Rev Growth</th><th>EBITDA Margin</th></tr>`;
    for (const comp of c.comps) {
      html += `<tr><td>${comp.name}</td><td>${comp.ticker}</td><td>${comp.market_cap}</td><td>${comp.ev_revenue}</td><td>${comp.ev_ebitda}</td><td>${comp.pe_ratio}</td><td>${comp.revenue_growth}</td><td>${comp.ebitda_margin}</td></tr>`;
    }
    html += `</table>`;
  }

  // DCF
  if (c.dcf_indicators) {
    const d = c.dcf_indicators;
    html += `<div class="dcf-box"><h3>DCF Valuation Indicators</h3>`;
    html += `<p><strong>WACC:</strong> ${d.wacc_range} | <strong>Terminal Growth:</strong> ${d.terminal_growth}</p>`;
    html += `<p><strong>Implied Value:</strong> Low ${d.implied_value_low} — Mid ${d.implied_value_mid} — High ${d.implied_value_high}</p>`;
    if (d.methodology_note) html += `<p><em>${d.methodology_note}</em></p>`;
    html += `</div>`;
  }

  // M&A
  if (c.ma_context) {
    const ma = c.ma_context;
    html += `<div class="ma-box"><h3>M&A Context</h3>`;
    if (ma.recent_sector_deals?.length) html += `<h4>Recent Sector Deals</h4><ul>${ma.recent_sector_deals.map(d => `<li>${d}</li>`).join('')}</ul>`;
    if (ma.potential_acquirers?.length) html += `<h4>Potential Acquirers</h4><ul>${ma.potential_acquirers.map(d => `<li>${d}</li>`).join('')}</ul>`;
    if (ma.precedent_transactions?.length) html += `<h4>Precedent Transactions</h4><ul>${ma.precedent_transactions.map(d => `<li>${d}</li>`).join('')}</ul>`;
    html += `</div>`;
  }

  // SWOT
  html += `<h3>SWOT Analysis</h3><div class="swot">`;
  html += `<div class="swot-box s-box"><strong>Strengths</strong><ul>${(c.strengths||[]).map(s=>`<li>${s}</li>`).join('')}</ul></div>`;
  html += `<div class="swot-box w-box"><strong>Weaknesses</strong><ul>${(c.weaknesses||[]).map(s=>`<li>${s}</li>`).join('')}</ul></div>`;
  html += `<div class="swot-box o-box"><strong>Opportunities</strong><ul>${(c.opportunities||[]).map(s=>`<li>${s}</li>`).join('')}</ul></div>`;
  html += `<div class="swot-box t-box"><strong>Threats</strong><ul>${(c.threats||[]).map(s=>`<li>${s}</li>`).join('')}</ul></div>`;
  html += `</div>`;

  // Risks
  if (c.risk_factors) {
    html += `<div class="risk-section"><h3>Risk Factors</h3>`;
    const rf = c.risk_factors;
    if (rf.company_specific?.length) html += `<h4>Company-Specific</h4><ul>${rf.company_specific.map(r=>`<li>${r}</li>`).join('')}</ul>`;
    if (rf.industry_macro?.length) html += `<h4>Industry/Macro</h4><ul>${rf.industry_macro.map(r=>`<li>${r}</li>`).join('')}</ul>`;
    if (rf.regulatory?.length) html += `<h4>Regulatory</h4><ul>${rf.regulatory.map(r=>`<li>${r}</li>`).join('')}</ul>`;
    html += `</div>`;
  }

  // Catalysts
  if (c.catalysts?.length) {
    html += `<h3>Upcoming Catalysts</h3>`;
    for (const cat of c.catalysts) html += `<div class="catalyst">${cat}</div>`;
  }

  // Investment Thesis
  if (c.investment_thesis) {
    html += `<h3>Investment Thesis</h3>`;
    html += `<div class="thesis-box bull"><strong>Bull Case:</strong> ${c.investment_thesis.bull_case}</div>`;
    html += `<div class="thesis-box base"><strong>Base Case:</strong> ${c.investment_thesis.base_case}</div>`;
    html += `<div class="thesis-box bear"><strong>Bear Case:</strong> ${c.investment_thesis.bear_case}</div>`;
  }

  html += `</div><hr>`;
}

if (comparativeAnalysis) {
  html += `<div class="overview-box"><h3>Comparative Analysis</h3><p>${comparativeAnalysis}</p></div>`;
}

html += `<div class="disclaimer"><strong>Disclaimer:</strong> This report was generated by an AI research agent and is for informational purposes only. Financial data may be based on estimates and AI knowledge. This does not constitute investment advice, a recommendation, or an offer to buy/sell securities. All figures should be independently verified using primary sources (SEC filings, Bloomberg, FactSet) before use in any client-facing materials or investment decisions. Past performance is not indicative of future results.</div>`;
html += `</body></html>`;

// === BUILD CSV ===
const csvHeaders = Object.keys(companyRows[0] || {});
let csv = csvHeaders.join(',') + '\n';
for (const row of companyRows) {
  csv += csvHeaders.map(h => '"' + String(row[h] || '').replace(/"/g, '""') + '"').join(',') + '\n';
}

// Comps CSV
if (compsRows.length) {
  csv += '\n\nCOMPS TABLE\n';
  const compsHeaders = Object.keys(compsRows[0]);
  csv += compsHeaders.join(',') + '\n';
  for (const row of compsRows) {
    csv += compsHeaders.map(h => '"' + String(row[h] || '').replace(/"/g, '""') + '"').join(',') + '\n';
  }
}

const csvBuffer = Buffer.from(csv, 'utf-8');
const dateStr = new Date().toISOString().split('T')[0];

return [{
  json: {
    htmlReport: html,
    from: $('Sanitize Email').item.json.from,
    subject: $('Sanitize Email').item.json.subject
  },
  binary: {
    data: {
      data: csvBuffer.toString('base64'),
      mimeType: 'text/csv',
      fileName: 'ib_research_' + dateStr + '.csv',
      fileExtension: 'csv'
    }
  }
}];
